SELECT COUNT(*) 
FROM drag_and_drop_events 
WHERE event_type != 'touch' AND drop_effect IN ('move', 'copy');

SELECT COUNT(*) AS total_settings
FROM application_settings
WHERE name LIKE 'Drag%';

SELECT *
FROM drag_data_stores
WHERE mode = 'Read/write mode' AND created_at < '2023-10-02 00:00:00';

SELECT value AS drop_zone_color
FROM application_settings
WHERE name = 'Drop Zone Color';

SELECT COUNT(DISTINCT e.event_id) 
FROM drag_and_drop_events e
WHERE e.custom_event_handler IN (0, 1);

SELECT drop_effect_id
FROM drop_effects
WHERE name = 'Move';

SELECT name 
FROM drop_effects 
WHERE drop_effect_id = 1;

SELECT name
FROM drag_data_stores
WHERE drag_data_store_id = 1;

SELECT DISTINCT user_id, application_id
FROM drag_and_drop_events
WHERE event_name = 'dragstart' AND drop_effect IN ('move', 'copy');

SELECT event_name
FROM drag_and_drop_events
WHERE LENGTH(drop_targets) = (SELECT MAX(LENGTH(drop_targets)) FROM drag_and_drop_events);
